-- name_gender lookup table (manual SQL, no app migrations)
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS name_gender (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  gender TEXT NOT NULL DEFAULT 'unknown' CHECK (lower(gender) IN ('male','female','robot','alien','unknown')),
  insert_date TEXT NOT NULL,
  verified INTEGER NOT NULL DEFAULT 0 CHECK (verified IN (0,1))
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_name_gender_name_nocase ON name_gender(name COLLATE NOCASE);
CREATE INDEX IF NOT EXISTS idx_name_gender_verified ON name_gender(verified, name COLLATE NOCASE);
